import Link from 'next/link';

export default function NewInventoryItemPage() {
  return (
    <div className="space-y-6 rounded-3xl border border-slate-200 bg-white p-6 shadow-sm sm:p-8">
      <div>
        <p className="text-sm uppercase tracking-[0.3em] text-slate-500">Add inventory item</p>
        <h1 className="mt-3 text-2xl font-semibold text-slate-900">Form coming soon</h1>
        <p className="mt-3 text-sm leading-6 text-slate-600">
          The inventory add form will let you create new guitars and other items. For now, you can return to the inventory list.
        </p>
      </div>
      <Link
        href="/inventory"
        className="inline-flex items-center justify-center rounded-2xl bg-slate-900 px-5 py-3 text-sm font-semibold text-white transition hover:bg-slate-800"
      >
        Back to inventory
      </Link>
    </div>
  );
}
